Update getPulsingColor to use cycling palette:

```go
func getPulsingColor(phase float64, paletteIndex int) lipgloss.Color {
    // Get current base color from cycling palette
    baseColor := colorPalette[paletteIndex]

    // Create dark and bright variants based on base
    // For simplicity, use fixed palette in function
    dark := lipgloss.Color("#996699")
    bright := lipgloss.Color("#ff66ff")

    // For a more sophisticated system, would generate variants from baseColor
    // by darkening/lightening the RGB values

    if phase < 0.5 {
        t := phase * 2
        return interpolateColor(dark, baseColor, t)
    } else {
        t := (phase - 0.5) * 2
        return interpolateColor(baseColor, bright, t)
    }
}
```

